mapper.select:
SELECT id FROM worker_report_outbox
WHERE publish_status = #{statusNew} AND next_attempt_at <= #{nowEpochMillis}
ORDER BY id ASC LIMIT 1

UPDATE worker_report_outbox
SET publish_status = #{statusPublishing}, updated_at = #{now}
WHERE id = #{id} AND publish_status = #{statusNew}
RETURNING id, payload_json AS payload_json

mapper.update:
UPDATE worker_report_outbox
SET publish_status = #{publishStatus}, attempt_count = #{attemptCount}, updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE worker_report_outbox
SET attempt_count = #{attemptCount}, next_attempt_at = #{nextAttemptAt}, updated_at = #{updatedAt},
    publish_status = #{publishStatus}
WHERE id = #{id}

UPDATE worker_report_outbox
SET publish_status = #{statusNew}, updated_at = #{now}
WHERE publish_status = #{statusPublishing} AND updated_at < #{cutoff}

UPDATE worker_report_outbox SET publish_status = #{publishStatus}, updated_at = #{now}, attempt_count =
    CASE WHEN attempt_count < #{maxAttempts} THEN #{maxAttempts} ELSE attempt_count END
WHERE id = #{id}
